/**
 * Core types for the Food Match scoring engine.
 */

/** User's response to a single quiz card. */
export type RatingValue = 1 | 0 | -1;

/** A single quiz card rating result. */
export interface Rating {
  ingredientIndex: number;
  value: RatingValue;
}

/** A cuisine direction with computed score and explanation. */
export interface CuisineScore {
  direction: string;
  label: string;
  score: number;
  topContributors: string[];
}

/** A flavor neighborhood (mode) affinity. */
export interface ModeAffinity {
  modeIndex: number;
  label: string;
  score: number;
  examples: string[];
}

/** A user's complete taste profile. */
export interface Profile {
  cuisineScores: CuisineScore[];
  modeAffinities: ModeAffinity[];
}

/** Encoded profile for URL sharing. */
export interface EncodedProfile {
  version: number;
  cuisines: number[];
  modes: { index: number; score: number }[];
}

/** Compatibility result between two profiles. */
export interface Comparison {
  sharedGround: {
    cuisines: CuisineScore[];
    modes: ModeAffinity[];
    summary: string;
  };
  conflicts: {
    direction: string;
    labelA: string;
    labelB: string;
    summary: string;
  }[];
  bridges: {
    ingredient: string;
    from: string;
    to: string;
    summary: string;
  }[];
  eatTogether: string;
}

/** Quiz card definition. */
export interface QuizCard {
  name: string;
  context: string;
  embeddingIndex: number;
}

/** Mode atlas entry. */
export interface ModeEntry {
  label: string;
  members: string[];
}

/** Cuisine direction definition. */
export interface CuisineDirection {
  id: string;
  label: string;
}

/**
 * Scoring engine: computes taste profiles from quiz ratings.
 *
 * All functions are pure — no side effects, no DOM, no state.
 * The math: user ratings × ingredient embeddings → preference vector,
 * then dot products against cuisine directions and mode centroids.
 */

import type { Rating, Profile, CuisineScore, ModeAffinity } from "./types";

/**
 * Compute the dot product of two vectors.
 *
 * Args:
 *   a: First vector.
 *   b: Second vector (same length as a).
 *
 * Returns:
 *   Scalar dot product.
 */
function dot(a: number[], b: number[]): number {
  let sum = 0;
  for (let i = 0; i < a.length; i++) {
    sum += a[i] * b[i];
  }
  return sum;
}

/**
 * Compute the L2 norm of a vector.
 *
 * Args:
 *   v: Input vector.
 *
 * Returns:
 *   Euclidean length.
 */
function norm(v: number[]): number {
  return Math.sqrt(dot(v, v));
}

/**
 * Normalize a vector to unit length. Returns zero vector if input is zero.
 *
 * Args:
 *   v: Input vector.
 *
 * Returns:
 *   Unit vector in the same direction, or zero vector.
 */
function normalize(v: number[]): number[] {
  const n = norm(v);
  if (n === 0) return v.map(() => 0);
  return v.map((x) => x / n);
}

/**
 * Build a user preference vector from quiz ratings and ingredient embeddings.
 *
 * Args:
 *   ratings: Array of user ratings (only scored ingredients, not skipped).
 *   embeddings: Matrix of ingredient embeddings (one row per quiz ingredient).
 *
 * Returns:
 *   Normalized 300-dim preference vector.
 */
export function buildPreferenceVector(
  ratings: Rating[],
  embeddings: number[][]
): number[] {
  const dim = embeddings[0].length;
  const prefVector = new Array(dim).fill(0);

  for (const { ingredientIndex, value } of ratings) {
    const embedding = embeddings[ingredientIndex];
    for (let i = 0; i < dim; i++) {
      prefVector[i] += value * embedding[i];
    }
  }

  return normalize(prefVector);
}

/**
 * Score cuisine affinities by projecting the preference vector onto cuisine directions.
 *
 * Args:
 *   prefVector: Normalized preference vector.
 *   cuisineVectors: Array of 8 cuisine direction vectors.
 *   cuisineLabels: Array of 8 cuisine direction labels.
 *   ratings: Original ratings for computing top contributors.
 *   embeddings: Ingredient embeddings for contribution analysis.
 *   ingredientNames: Names of quiz ingredients for explanation.
 *
 * Returns:
 *   Array of CuisineScore sorted by score descending.
 */
export function scoreCuisines(
  prefVector: number[],
  cuisineVectors: number[][],
  cuisineLabels: { id: string; label: string }[],
  ratings: Rating[],
  embeddings: number[][],
  ingredientNames: string[]
): CuisineScore[] {
  const scores: CuisineScore[] = cuisineLabels.map((cuisine, i) => {
    const score = dot(prefVector, cuisineVectors[i]);

    // Find top contributors: which rated ingredients project most onto this direction
    const contributions = ratings
      .filter((r) => r.value !== 0)
      .map((r) => ({
        name: ingredientNames[r.ingredientIndex],
        contribution: r.value * dot(embeddings[r.ingredientIndex], cuisineVectors[i]),
      }))
      .sort((a, b) => Math.abs(b.contribution) - Math.abs(a.contribution))
      .slice(0, 3)
      .filter((c) => c.contribution > 0)
      .map((c) => c.name);

    return {
      direction: cuisine.id,
      label: cuisine.label,
      score,
      topContributors: contributions,
    };
  });

  return scores.sort((a, b) => b.score - a.score);
}

/**
 * Score mode affinities by projecting the preference vector onto mode centroids.
 *
 * Args:
 *   prefVector: Normalized preference vector.
 *   modeCentroids: Array of mode centroid vectors.
 *   modeEntries: Array of mode metadata (labels, members).
 *
 * Returns:
 *   Array of ModeAffinity sorted by score descending.
 */
export function scoreModes(
  prefVector: number[],
  modeCentroids: number[][],
  modeEntries: { label: string; members: string[] }[]
): ModeAffinity[] {
  const affinities: ModeAffinity[] = modeEntries.map((mode, i) => ({
    modeIndex: i,
    label: mode.label,
    score: dot(prefVector, modeCentroids[i]),
    examples: mode.members.slice(0, 4),
  }));

  return affinities.sort((a, b) => b.score - a.score);
}

/**
 * Build a complete taste profile from quiz ratings.
 *
 * Args:
 *   ratings: User's quiz ratings (excluding skipped/can't-eat).
 *   embeddings: Quiz ingredient embedding matrix.
 *   cuisineVectors: 8 cuisine direction vectors.
 *   cuisineLabels: 8 cuisine labels.
 *   modeCentroids: Mode centroid vectors.
 *   modeEntries: Mode metadata.
 *   ingredientNames: Quiz ingredient names.
 *
 * Returns:
 *   Complete Profile with top cuisines and modes.
 */
export function buildProfile(
  ratings: Rating[],
  embeddings: number[][],
  cuisineVectors: number[][],
  cuisineLabels: { id: string; label: string }[],
  modeCentroids: number[][],
  modeEntries: { label: string; members: string[] }[],
  ingredientNames: string[]
): Profile {
  const prefVector = buildPreferenceVector(ratings, embeddings);

  const cuisineScores = scoreCuisines(
    prefVector,
    cuisineVectors,
    cuisineLabels,
    ratings,
    embeddings,
    ingredientNames
  );

  const modeAffinities = scoreModes(prefVector, modeCentroids, modeEntries);

  return {
    cuisineScores: cuisineScores.slice(0, 3),
    modeAffinities: modeAffinities.slice(0, 5),
  };
}

/**
 * URL codec: encodes/decodes profiles to/from URL-safe strings.
 *
 * Binary format:
 *   [version: 1 byte]
 *   [8 cuisine scores: 8 bytes, each uint8 0-255]
 *   [mode count: 1 byte]
 *   [per mode: index uint8 + score uint8 = 2 bytes × N]
 *
 * Total: 10 + 2N bytes → base64url encoded.
 */

import type { EncodedProfile, Profile } from "./types";

const CURRENT_VERSION = 1;
const NUM_CUISINES = 8;
const MAX_MODES = 5;

/**
 * Quantize a float score to uint8 (0-255).
 * Maps [-1, 1] → [0, 255].
 *
 * Args:
 *   score: Float in approximately [-1, 1] range.
 *
 * Returns:
 *   Uint8 value.
 */
function quantize(score: number): number {
  const clamped = Math.max(-1, Math.min(1, score));
  return Math.round((clamped + 1) * 127.5);
}

/**
 * Dequantize uint8 back to float.
 * Maps [0, 255] → [-1, 1].
 *
 * Args:
 *   byte: Uint8 value.
 *
 * Returns:
 *   Float score.
 */
function dequantize(byte: number): number {
  return (byte / 127.5) - 1;
}

/**
 * Encode a base64url string from a Uint8Array (no padding).
 *
 * Args:
 *   bytes: Binary data.
 *
 * Returns:
 *   Base64url string without padding.
 */
function toBase64Url(bytes: Uint8Array): string {
  const binStr = Array.from(bytes, (b) => String.fromCharCode(b)).join("");
  return btoa(binStr).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
}

/**
 * Decode a base64url string to Uint8Array.
 *
 * Args:
 *   str: Base64url string (with or without padding).
 *
 * Returns:
 *   Binary data.
 */
function fromBase64Url(str: string): Uint8Array {
  const base64 = str.replace(/-/g, "+").replace(/_/g, "/");
  const padded = base64 + "=".repeat((4 - (base64.length % 4)) % 4);
  const binStr = atob(padded);
  return Uint8Array.from(binStr, (c) => c.charCodeAt(0));
}

/**
 * Encode a Profile into a URL-safe string.
 *
 * Args:
 *   profile: The user's computed profile.
 *
 * Returns:
 *   Base64url encoded string (~28 characters).
 */
export function encodeProfile(profile: Profile): string {
  const modeCount = Math.min(profile.modeAffinities.length, MAX_MODES);
  const totalBytes = 1 + NUM_CUISINES + 1 + modeCount * 2;
  const buffer = new Uint8Array(totalBytes);

  let offset = 0;

  // Version
  buffer[offset++] = CURRENT_VERSION;

  // 8 cuisine scores
  for (let i = 0; i < NUM_CUISINES; i++) {
    const score = i < profile.cuisineScores.length ? profile.cuisineScores[i].score : 0;
    buffer[offset++] = quantize(score);
  }

  // Mode count
  buffer[offset++] = modeCount;

  // Mode entries
  for (let i = 0; i < modeCount; i++) {
    const mode = profile.modeAffinities[i];
    buffer[offset++] = mode.modeIndex & 0xff;
    buffer[offset++] = quantize(mode.score);
  }

  return toBase64Url(buffer);
}

/**
 * Decode a URL-safe string back into an EncodedProfile.
 *
 * Args:
 *   encoded: Base64url string from the URL hash.
 *
 * Returns:
 *   Decoded profile data, or null if invalid.
 */
export function decodeProfile(encoded: string): EncodedProfile | null {
  try {
    const bytes = fromBase64Url(encoded);

    if (bytes.length < 10) return null;

    let offset = 0;
    const version = bytes[offset++];

    if (version !== CURRENT_VERSION) return null;

    // 8 cuisine scores
    const cuisines: number[] = [];
    for (let i = 0; i < NUM_CUISINES; i++) {
      cuisines.push(dequantize(bytes[offset++]));
    }

    // Mode count
    const modeCount = bytes[offset++];
    if (modeCount > MAX_MODES) return null;
    if (bytes.length < offset + modeCount * 2) return null;

    // Mode entries
    const modes: { index: number; score: number }[] = [];
    for (let i = 0; i < modeCount; i++) {
      const index = bytes[offset++];
      const score = dequantize(bytes[offset++]);
      modes.push({ index, score });
    }

    return { version, cuisines, modes };
  } catch {
    return null;
  }
}

/**
 * Get the full shareable URL for a profile.
 *
 * Args:
 *   profile: The user's computed profile.
 *
 * Returns:
 *   Full URL with profile encoded in hash.
 */
export function getShareableUrl(profile: Profile): string {
  const encoded = encodeProfile(profile);
  return `${window.location.origin}${window.location.pathname}#p=${encoded}`;
}

/**
 * Extract an encoded profile from the current URL hash, if present.
 *
 * Returns:
 *   Decoded profile or null if no valid profile in URL.
 */
export function getProfileFromUrl(): EncodedProfile | null {
  const hash = window.location.hash;
  const match = hash.match(/^#p=(.+)$/);
  if (!match) return null;
  return decodeProfile(match[1]);
}

/**
 * Comparison engine: overlays two profiles to find compatibility.
 *
 * Produces shared ground (primary), conflicts, and bridge suggestions.
 */

import type { Profile, Comparison, CuisineScore, ModeAffinity } from "./types";

const SHARED_THRESHOLD = 0.1;
const CONFLICT_THRESHOLD = 0.3;
const BRIDGE_THRESHOLD = 0.05;

/**
 * Compare two profiles and produce a compatibility result.
 *
 * Args:
 *   profileA: First user's profile (the sharer).
 *   profileB: Second user's profile (the viewer).
 *
 * Returns:
 *   Comparison with shared ground, conflicts, bridges, and eat-together suggestion.
 */
export function compareProfiles(
  profileA: Profile,
  profileB: Profile
): Comparison {
  const sharedCuisines = findSharedCuisines(profileA.cuisineScores, profileB.cuisineScores);
  const sharedModes = findSharedModes(profileA.modeAffinities, profileB.modeAffinities);
  const conflicts = findConflicts(profileA.cuisineScores, profileB.cuisineScores);
  const bridges = findBridges(profileA.modeAffinities, profileB.modeAffinities);

  const sharedSummary = buildSharedSummary(sharedCuisines, sharedModes);
  const eatTogether = buildEatTogetherSuggestion(sharedCuisines, sharedModes);

  return {
    sharedGround: {
      cuisines: sharedCuisines,
      modes: sharedModes,
      summary: sharedSummary,
    },
    conflicts,
    bridges,
    eatTogether,
  };
}

/**
 * Find cuisines where both users score above threshold.
 */
function findSharedCuisines(
  scoresA: CuisineScore[],
  scoresB: CuisineScore[]
): CuisineScore[] {
  const shared: CuisineScore[] = [];

  for (const a of scoresA) {
    const b = scoresB.find((s) => s.direction === a.direction);
    if (b && a.score > SHARED_THRESHOLD && b.score > SHARED_THRESHOLD) {
      shared.push({
        direction: a.direction,
        label: a.label,
        score: (a.score + b.score) / 2,
        topContributors: [...new Set([...a.topContributors, ...b.topContributors])].slice(0, 4),
      });
    }
  }

  return shared.sort((a, b) => b.score - a.score);
}

/**
 * Find modes where both users have high affinity.
 */
function findSharedModes(
  modesA: ModeAffinity[],
  modesB: ModeAffinity[]
): ModeAffinity[] {
  const shared: ModeAffinity[] = [];

  for (const a of modesA) {
    const b = modesB.find((m) => m.modeIndex === a.modeIndex);
    if (b && a.score > SHARED_THRESHOLD && b.score > SHARED_THRESHOLD) {
      shared.push({
        modeIndex: a.modeIndex,
        label: a.label,
        score: (a.score + b.score) / 2,
        examples: a.examples,
      });
    }
  }

  return shared.sort((a, b) => b.score - a.score);
}

/**
 * Find cuisine directions where one scores high and the other low.
 */
function findConflicts(
  scoresA: CuisineScore[],
  scoresB: CuisineScore[]
): Comparison["conflicts"] {
  const conflicts: Comparison["conflicts"] = [];

  for (const a of scoresA) {
    const b = scoresB.find((s) => s.direction === a.direction);
    if (b && Math.abs(a.score - b.score) > CONFLICT_THRESHOLD) {
      const higher = a.score > b.score ? "You" : "They";
      const lower = a.score > b.score ? "they" : "you";
      conflicts.push({
        direction: a.direction,
        labelA: a.label,
        labelB: b.label,
        summary: `${higher} lean toward ${a.label} flavors, but ${lower} rated those ingredients lower.`,
      });
    }
  }

  return conflicts;
}

/**
 * Find modes where one person is high and the other is neutral (not negative).
 * These are opportunities to introduce new flavors.
 */
function findBridges(
  modesA: ModeAffinity[],
  modesB: ModeAffinity[]
): Comparison["bridges"] {
  const bridges: Comparison["bridges"] = [];

  // Check A's top modes that B hasn't explored
  for (const a of modesA.slice(0, 5)) {
    const b = modesB.find((m) => m.modeIndex === a.modeIndex);
    if (b && a.score > SHARED_THRESHOLD && b.score >= -BRIDGE_THRESHOLD && b.score < SHARED_THRESHOLD) {
      bridges.push({
        ingredient: a.examples[0] || a.label,
        from: "them",
        to: "you",
        summary: `They love ${a.label} (like ${a.examples.slice(0, 2).join(", ")}). You haven't explored it much — you might enjoy it.`,
      });
    }
  }

  // Check B's top modes that A hasn't explored
  for (const b of modesB.slice(0, 5)) {
    const a = modesA.find((m) => m.modeIndex === b.modeIndex);
    if (a && b.score > SHARED_THRESHOLD && a.score >= -BRIDGE_THRESHOLD && a.score < SHARED_THRESHOLD) {
      bridges.push({
        ingredient: b.examples[0] || b.label,
        from: "you",
        to: "them",
        summary: `You love ${b.label} (like ${b.examples.slice(0, 2).join(", ")}). They might be open to trying it.`,
      });
    }
  }

  return bridges.slice(0, 3);
}

/**
 * Build a natural-language summary of shared ground.
 */
function buildSharedSummary(
  cuisines: CuisineScore[],
  modes: ModeAffinity[]
): string {
  if (cuisines.length === 0 && modes.length === 0) {
    return "You have pretty different palates! But that can make dining together an adventure.";
  }

  const cuisineNames = cuisines.slice(0, 2).map((c) => c.label);
  const modeExamples = modes.slice(0, 2).flatMap((m) => m.examples.slice(0, 2));

  let summary = `You both gravitate toward ${cuisineNames.join(" and ")} flavors`;
  if (modeExamples.length > 0) {
    summary += `, especially ingredients like ${modeExamples.join(", ")}`;
  }
  summary += ".";

  return summary;
}

/**
 * Generate a concrete eat-together suggestion from shared ground.
 */
function buildEatTogetherSuggestion(
  cuisines: CuisineScore[],
  modes: ModeAffinity[]
): string {
  if (cuisines.length === 0) {
    return "Try a restaurant with a diverse menu so you can each find something you love.";
  }

  const topCuisine = cuisines[0];
  const topMode = modes.length > 0 ? modes[0] : null;

  let suggestion = `Look for a ${topCuisine.label} restaurant`;
  if (topMode) {
    suggestion += ` that features ${topMode.label.toLowerCase()} dishes`;
    if (topMode.examples.length > 0) {
      suggestion += ` (think ${topMode.examples.slice(0, 3).join(", ")})`;
    }
  }
  suggestion += ". You'll both enjoy it.";

  return suggestion;
}

/**
 * Barrel export for the scoring engine.
 */

export { buildProfile, buildPreferenceVector, scoreCuisines, scoreModes } from "./scoring";
export { encodeProfile, decodeProfile, getShareableUrl, getProfileFromUrl } from "./url-codec";
export { compareProfiles } from "./compare";
export type {
